SELECT r.*, ste.site_nm AS site_nm, usr.user_nm AS admin_user_nm, cd_cs.code_label AS chatt_status_cd_nm FROM cm_chatt_room r LEFT JOIN sy_site ste ON ste.site_id = r.site_id LEFT JOIN sy_user usr ON usr.user_id = r.admin_user_id LEFT JOIN sy_code cd_cs ON cd_cs.code_grp = 'CHATT_STATUS' AND cd_cs.code_value = r.chatt_status_cd
ORDER BY r.chatt_room_id ASC ORDER BY r.chatt_room_id DESC ORDER BY r.member_nm ASC ORDER BY r.member_nm DESC ORDER BY r.reg_date ASC ORDER BY r.reg_date DESC ORDER BY r.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

