site_id = #{siteId}, member_id = #{memberId}, member_nm = #{memberNm}, admin_user_id = #{adminUserId}, subject = #{subject}, chatt_status_cd = #{chattStatusCd}, chatt_status_cd_before = #{chattStatusCdBefore}, last_msg_date = #{lastMsgDate}, member_unread_cnt = #{memberUnreadCnt}, admin_unread_cnt = #{adminUnreadCnt}, chatt_memo = #{chattMemo}, close_date = #{closeDate}, close_reason = #{closeReason}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE chatt_room_id = #{chattRoomId}
